//! DEBUG: dump the sovereign FLUX CLIP pooled vector [768] for a comma-separated
//! list of CLIP token ids, for numeric cross-check (cosine) against a HF
//! CLIPTextModel pooled output. Emits a flat little-endian f32 binary.
use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_flux_txt2img::debug_flux_clip_pooled;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 4 {
        eprintln!("usage: flux-clip-dump <knot> <clip_ids_csv> <out.bin>");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let clip_ids: Vec<i64> = args[2]
        .split(',')
        .filter_map(|s| s.trim().parse::<i64>().ok())
        .collect();
    let out = &args[3];

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");
    let pooled = debug_flux_clip_pooled(knot_path, &knot, &clip_ids).expect("clip pooled");

    let n = pooled.len() as f32;
    let mean = pooled.iter().sum::<f32>() / n;
    let var = pooled.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let mn = pooled.iter().cloned().fold(f32::INFINITY, f32::min);
    let mx = pooled.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    eprintln!(
        "clip pooled len={} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
        pooled.len(),
        mean,
        var.sqrt(),
        mn,
        mx
    );
    let mut f = std::fs::File::create(out).unwrap();
    for x in &pooled {
        f.write_all(&x.to_le_bytes()).unwrap();
    }
    eprintln!("wrote {out} ({} f32)", pooled.len());
}
